/**
 * Notification channel interface.
 *
 * Each channel (email, SMS, Slack, etc.) implements this interface and
 * subscribes to notification:send events on the EventBus. The notification
 * service publishes events; channels handle delivery independently.
 *
 * To add a new channel:
 * 1. Create a class implementing NotificationChannel
 * 2. Register it with the NotificationService via addChannel()
 */

import type { NotificationSendEvent } from '../../events/event-types.js';

export interface NotificationChannel {
  /** Unique channel name (e.g. 'email', 'sms', 'slack'). */
  readonly name: string;

  /**
   * Deliver a notification through this channel.
   * Called by the EventBus when a notification:send event matches this channel.
   */
  send(event: NotificationSendEvent): void | Promise<void>;
}

/**
 * Email notification channel.
 *
 * Handles delivery of notifications via email. Currently stores sent
 * emails in memory for testing/demo purposes. In production, this would
 * integrate with an SMTP service or email API (e.g. SendGrid, SES).
 */

import type { NotificationSendEvent } from '../../events/event-types.js';
import { Logger } from '../../utils/logger.js';
import type { NotificationChannel } from './notification-channel.js';

export interface SentEmail {
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailNotificationChannel implements NotificationChannel {
  readonly name = 'email';
  private logger = new Logger('EmailChannel');
  private sentEmails: SentEmail[] = [];

  /**
   * Send a notification via email.
   */
  send(event: NotificationSendEvent): void {
    const email: SentEmail = {
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${event.recipient}: ${event.subject}`);
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Uses the EventBus pattern throughout:
 * 1. Listens for domain events (order:created, order:status-changed)
 * 2. Publishes notification:send events for channel handlers to deliver
 *
 * Channel handlers (email, SMS, etc.) subscribe to notification:send events
 * and handle delivery for their respective channel. This makes the system
 * extensible — new channels can be added without modifying this service.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and dispatching to channels
 * - NotificationChannel implementations for actual delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  NotificationSendEvent,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import { Logger } from '../utils/logger.js';
import type { NotificationChannel } from './channels/notification-channel.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private channels: Map<string, NotificationChannel> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerDomainHandlers();
    this.registerNotificationHandler();
  }

  /**
   * Add a notification channel. The channel will receive notification:send
   * events matching its name via the EventBus.
   */
  addChannel(channel: NotificationChannel): void {
    this.channels.set(channel.name, channel);
    this.logger.info(`Channel registered: ${channel.name}`);
  }

  /**
   * Register handlers for domain events that trigger notifications.
   */
  private registerDomainHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Register handler for notification:send events.
   * Records the notification and delegates to the appropriate channel.
   */
  private registerNotificationHandler(): void {
    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      const notification: Notification = {
        id: generateNotificationId(),
        recipient: event.recipient,
        subject: event.subject,
        body: event.body,
        channel: event.channel,
        sentAt: new Date(),
      };
      this.notifications.push(notification);

      const channel = this.channels.get(event.channel);
      if (channel) {
        channel.send(event);
      }

      this.logger.info(
        `Notification ${notification.id} sent via ${event.channel} to ${event.recipient}`,
      );
    });
  }

  /**
   * Handle order created event — send confirmation to user via email.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update via email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Publish a notification:send event to the EventBus.
   * Channel handlers will pick it up and handle delivery.
   */
  private sendNotification(params: {
    channel: string;
    recipient: string;
    subject: string;
    body: string;
  }): void {
    const event: NotificationSendEvent = {
      type: 'notification:send',
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      timestamp: new Date(),
    };
    // Emit synchronously within the current event handler chain.
    // The EventBus emit is async but we fire-and-forget here since
    // notification delivery is a side effect, not a blocking operation.
    void this.eventBus.emit(event);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

